code = """import json

# Load the emergency/FEMA funding records
funding_records = locals()['var_functions.query_db:52']

# Load civic documents to extract status information
docs_file = locals()['var_functions.query_db:42']
with open(docs_file, 'r') as f:
    civic_docs = json.load(f)

# Initialize final results
final_results = []

# For each emergency/FEMA funded project
for project in funding_records:
    proj_name = project['Project_Name']
    proj_name_lower = proj_name.lower()
    
    # Initialize with defaults
    status = 'not started'
    
    # Clean project name for matching (remove suffixes)
    base_name = proj_name.replace(' (FEMA Project)', '').replace(' (FEMA/CalOES Project)', '').replace(' (CalJPIA/FEMA Project)', '').strip()
    
    # Search for status in civic documents
    for doc in civic_docs:
        doc_text = doc['text'].lower()
        
        # Check if base project name appears in document
        if base_name.lower() in doc_text:
            # Check for construction/completion status
            if 'under construction' in doc_text or 'construction was completed' in doc_text:
                status = 'completed'
            # Check for design phase
            elif 'design' in doc_text and 'complete design' not in doc_text:
                status = 'design'
    
    # Determine project type
    proj_type = 'disaster' if 'fema' in proj_name_lower else 'capital'
    
    # Add to results
    final_results.append({
        'Project_Name': proj_name,
        'Funding_Source': project['Funding_Source'],
        'Amount': f"${int(project['Amount']):,}",
        'Status': status,
        'Type': proj_type
    })

# Format as a readable answer
answer = "EMERGENCY/FEMA RELATED PROJECTS - SUMMARY\n"
answer += "=" * 80 + "\n\n"

for result in final_results:
    answer += f"Project: {result['Project_Name']}\n"
    answer += f"  Funding Source: {result['Funding_Source']}\n"
    answer += f"  Amount: {result['Amount']}\n"
    answer += f"  Status: {result['Status']}\n"
    answer += f"  Type: {result['Type']}\n"
    answer += "\n"

answer += f"Total Projects Found: {len(final_results)}\n"

print('__RESULT__:')
print(answer)"""

